+import { $internal } from '../common';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import type { Trait, TraitRecord } from '../trait/types';
+import { $aspect } from './symbols';
+import type { Aspect, AspectInput, AspectRecord, AspectTraits } from './types';
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | null | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<AspectTraits<T>> {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+
+    for (const input of inputs) {
+        const constituents = isAspect(input) ? input.traits : [input as Trait];
+        for (const trait of constituents) {
+            if (isRelation(trait) || trait[$internal]?.relation) {
+                throw new Error('Koota: Relations cannot be constituents of an aspect.');
+            }
+            for (const field of Object.keys(trait.schema as Schema)) {
+                if (fields.has(field)) {
+                    throw new Error(`Koota: Aspect constituents overlap on field "${field}".`);
+                }
+                fields.add(field);
+                schema[field] = (trait.schema as Record<string, unknown>)[field];
+            }
+            traits.push(trait);
+        }
+    }
+
+    return Object.freeze({
+        [$aspect]: true as const,
+        id: aspectId++,
+        traits: Object.freeze(traits) as AspectTraits<T>,
+        schema: Object.freeze(schema) as AspectRecord<AspectTraits<T>>,
+    });
+}
