+function createAspectQueryResult<T extends QueryParameter[]>(
+    world: World,
+    entities: Entity[],
+    params: T
+): QueryResult<T> {
+    const results = Object.assign(entities, {
+        readEach(callback: any) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                callback(readAspectState(entity, params), entity, i);
+            }
+            return results;
+        },
+        updateEach(callback: any, options: QueryResultOptions = { changeDetection: 'auto' }) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = readAspectState(entity, params);
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                for (let j = 0; j < params.length; j++) {
+                    const param = params[j];
+                    if (isAspect(param)) entity.set(param, state[j], options.changeDetection !== 'never');
+                    else if ((param as Trait)[$internal] && (param as Trait)[$internal].type !== 'tag') {
+                        entity.set(param as Trait, state[j], options.changeDetection !== 'never');
+                    }
+                }
+            }
+            return results;
+        },
+        useStores(callback: any) {
+            callback([], entities);
+            return results;
+        },
+        select<U extends QueryParameter[]>(...selected: U) {
+            return createAspectQueryResult(world, entities, selected);
+        },
+        sort(callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)) {
+            Array.prototype.sort.call(entities, callback);
+            return results;
+        },
+    });
+    return results as QueryResult<T>;
+}
+
+function readAspectState(entity: Entity, params: QueryParameter[]) {
+    const state: unknown[] = [];
+    for (const param of params) {
+        if (isAspect(param)) {
+            state.push(entity.get(param));
+        } else if ((param as Trait)[$internal] && (param as Trait)[$internal].type !== 'tag') {
+            state.push(entity.get(param as Trait));
+        }
+    }
+    return state;
+}
